        | Self::Echo { .. }
        | Self::BitArray { .. }
        | Self::RecordUpdate { .. }
        | Self::NegateBool { .. }
        | Self::NegateInt { .. }
        | Self::Invalid { .. } => false,
    }
}

pub fn is_zero_compile_time_number(&self) -> bool {
    match self {
        Self::Int { int_value, .. } => int_value == &BigInt::ZERO,
