        | Self::ModuleSelect { location, .. }
        | Self::RecordAccess { location, .. }
        | Self::PositionalAccess { location, .. }
        | Self::RecordUpdate { location, .. }
        | Self::Invalid { location, .. } => *location,
        Self::Block { statements, .. } => statements.last().location(),
    }
}

